CREATE TABLE IF NOT EXISTS vault_config (id INTEGER PRIMARY KEY CHECK(id=1), sealed INTEGER NOT NULL DEFAULT 1, master_key_salt BLOB NOT NULL, master_key_verify BLOB NOT NULL, scrypt_N INTEGER NOT NULL DEFAULT 16384, scrypt_r INTEGER NOT NULL DEFAULT 8, scrypt_p INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS vault_folders (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, name TEXT NOT NULL, parent_folder_id TEXT REFERENCES vault_folders(id) ON DELETE SET NULL, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE(project_id, name, parent_folder_id));
CREATE TABLE IF NOT EXISTS vault_items (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, folder_id TEXT REFERENCES vault_folders(id) ON DELETE SET NULL, name TEXT NOT NULL, type TEXT NOT NULL CHECK(type IN ('login','api_key','note','oauth')), tags TEXT DEFAULT '[]', urls TEXT DEFAULT '[]', username TEXT, encrypted BLOB NOT NULL, wrapped_kek BLOB NOT NULL, version INTEGER NOT NULL DEFAULT 1, access_policy TEXT NOT NULL DEFAULT '{"mode":"restricted"}', expires_at TEXT, lease_duration_seconds INTEGER, last_accessed_at TEXT, access_count INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE(project_id, folder_id, name));
CREATE TABLE IF NOT EXISTS vault_audit_log (id INTEGER PRIMARY KEY AUTOINCREMENT, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, event_type TEXT NOT NULL CHECK(event_type IN ('vault_sealed','vault_unsealed','vault_unseal_failed','secret_created','secret_read','secret_updated','secret_deleted','secret_rotated','secret_revealed','secret_copied','folder_created','folder_deleted','master_key_rotated','policy_updated','export_created','import_executed','access_denied')), item_id TEXT, actor TEXT NOT NULL, details TEXT, ip_address TEXT, user_agent TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE INDEX IF NOT EXISTS idx_vault_items_project ON vault_items(project_id, folder_id);
CREATE INDEX IF NOT EXISTS idx_vault_items_type ON vault_items(project_id, type);
CREATE INDEX IF NOT EXISTS idx_vault_audit_project ON vault_audit_log(project_id, created_at);
CREATE INDEX IF NOT EXISTS idx_vault_audit_item ON vault_audit_log(item_id);
CREATE INDEX IF NOT EXISTS idx_vault_folders_project ON vault_folders(project_id);
